var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"끙...... 끙......","JPN":"うーん……うーん……","ENG":"Oof... Oof...","TWN":"噢……噢……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"아얏! 새끼발가락 박았어......!","JPN":"痛ぁっ！　小指ぶつけちゃった……！","ENG":"Ouch! My pinky toe!","TWN":"痛死了！！踢到腳指頭了……！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"아이참, 누가 운반로에 공구상자 놔둔 거에요?","JPN":"もうっ、運搬経路に工具箱を置いたのは誰なのです？","ENG":"Who in their right mind left their toolbox on the transit lane?","TWN":"討厭，是誰把工具箱放到運輸道上的？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"이러면 사고 난다고 제가 몇 번이나 말했는지 알아요?","JPN":"こんな事したら危ないって何度も言いましたよね？","ENG":"How many times have I told you that doing that can lead to an accident?","TWN":"我都說幾遍了，這樣會發生危險的。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"헉?! 고, 공구상자가 아니라 혹시...... 사장님?","JPN":"ハッ！？　も、もしや……工具箱じゃなくて……社長？","ENG":"Eek?! I-it's not a toolbox... Are you the CEO?","TWN":"啊！！這、這不是工具箱……是老闆？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"으아아아, 죄송합니다!","JPN":"うわあああ、すみません！","ENG":"Ahhhh, I'm sorry!","TWN":"哇啊啊啊啊，非常抱歉！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"사장님을 걷어차다니 초면부터 엄청난 실례를......","JPN":"社長を蹴っ飛ばすなんて、初対面でありえないご無礼を……","ENG":"I can't believe I kicked you in our first meeting...","TWN":"居然踢了初次見面的老闆，真是太失禮了……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"겨, 격납고엔 어쩐 일로 오셨나요?","JPN":"か、格納庫には何のご用なのです？","ENG":"W-what brings you to the hangar?","TWN":"老、老闆您來機庫有什麼事情呢？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"혀, 현장시찰?","JPN":"げ、現場視察？","ENG":"A-an on-site inspection?","TWN":"視、視察現場？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"으으, 서, 설마 저 잘리는 건 아니겠죠?","JPN":"うぅ……ま、まさか私……クビですか？","ENG":"Uh, I-I'm not getting fired, am I?","TWN":"哇啊，我、我不會被炒魷魚了吧？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"봐, 봐주신다고요?","JPN":"ゆ、許していただけるのです？","ENG":"Y-you'll let this one pass?","TWN":"什麼？您說您是來視察我的工作內容？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"감사합니다! 저 정말 열심히 할게요!","JPN":"ありがとうございます！　私、頑張るのですっ！","ENG":"Thank you! I'll really give it my all!","TWN":"非常感謝！！我會更加努力的！！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"아, 이곳은 회사의 함선을 관리하는 곳이에요.","JPN":"あの、ここは会社の艦船を管理する場所なのです。","ENG":"Ah, this is where we take care of the company ships.","TWN":"啊，這裡是公司管理艦船的地方。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"손상된 함선을 정비하거나 폐기가 필요한 함선의 해체도 담당하고 있어요.","JPN":"損傷した艦船を整備したり、廃棄する艦船を解体したりするのですよ。","ENG":"We also repair damaged ships, and salvage ships that need to be disassembled.","TWN":"我們負責修理損壞的艦船，也負責拆除報廢的艦船。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"함선도 직접 만들 수 있냐고요......?","JPN":"艦船をここで作れるのかって……？","ENG":"Can we construct our own ships?","TWN":"您問能不能建造自己的艦船嗎……？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"도, 돈과 소재가 많이 들긴 하지만,","JPN":"お、お金と素材がたくさんいりますけど、","ENG":"I-it'll take a lot of money and materials,","TWN":"那，那樣雖然會花費很多金錢和材料，"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"필요만 하시다면 물론 만들어 드릴 수 있죠!","JPN":"必要ならばもちろん作ることも可能なのです！","ENG":"but if you require one, we can make it for you!","TWN":"但只要有需要我們就做得到！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"헤헤, 실은 함선을 제 손으로 직접 만들어 보는 게 소원이었거든요......","JPN":"えへへ、実は艦船を自分で作ってみるのが夢だったのですよ……","ENG":"Heh, it was actually a dream of mine to build a ship...","TWN":"嘿嘿，事實上，親手建造一艘艦船也是我的願望……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};